class Solution {
    public int magicalString(int n) {
        int[] s = new int[n + 1];
        s[1] = 1;
        int p = 2, i = 1;
        int one = 1, two = 1;
        while (i <= n) {
            int count = s[p];
            for (int j = 1; j <= count; j++) {
                s[++i] = (j == 1) ? one : two;
                if (j == 1) one++;
                else two++;
            }
            p++;
        }
        return s[n];
    }
}
